  res.send('Hello World!');
});

app.listen(3000, () => {
  console.log('Server running on http://localhost:3000');
});
```

### Explanation:
- `app.use()` registers the middleware for all routes.
- `Date.now()` records the start time.
- `res.on('finish', ...)` waits until the response is sent to calculate the total time.
- Logs the HTTP method, URL, and response time in milliseconds.

This is a common pattern for simple request logging in Express.

In TypeScript, both `type` aliases and `interface` are used to define the shape of objects and types, but they have some differences and use cases.

### Key Differences

| Aspect               | `interface`                                      | `type` alias                                  |
|----------------------|-------------------------------------------------|-----------------------------------------------|
| **Declaration merging** | Supports declaration merging (multiple interfaces with the same name get merged) | Does **not** support declaration merging     |
| **Extending**         | Can extend one or multiple interfaces            | Can create intersections with `&`            |
| **Capabilities**      | Primarily for object shapes and classes          | Can represent primitives, unions, tuples, mapped types, etc. |
| **Syntax**            | `interface Foo { ... }`                           | `type Foo = ...`                              |
| **Use with classes**  | Interfaces can be implemented by classes         | Types cannot be implemented, only used for type checking |

### When to use each?

- **Use `interface` when:**
  - You want to define the shape of an object or class.
  - You expect your type to be extended or merged later.
  - You want to take advantage of declaration merging.
  - You want to implement the type in a class.

- **Use `type` when:**
  - You need to define a union, tuple, or other complex types.
  - You want to alias primitives or other types.
  - You want to compose types using intersections or unions.
  - You don't need declaration merging.

### Examples

```ts
// Interface example
interface Person {
  name: string;
  age: number;
}

// Declaration merging
interface Person {
  location?: string;
}

// Person now has name, age, and optional location

// Type alias example
type ID = string | number;

type Coordinates = [number, number];

// Intersection type
type Employee = Person & { employeeId: number };
```

### Summary

- Use **`interface`** for defining object shapes and when you want to leverage declaration merging or class implementation.
- Use **`type`** for more flexible type definitions like unions, tuples, primitives, and intersections.

References:  
- [TypeScript Handbook - Interfaces](https://www.typescriptlang.org/docs/handbook/interfaces.html)  
- [TypeScript Handbook - Advanced Types](https://www.typescriptlang.org/docs/handbook/advanced-types.html#type-aliases)

Here's a TypeScript discriminated union type for API responses that can be either a `Success` with data or an `Error` with a message, along with a type guard function:

```typescript
// Define the discriminated union types
type ApiResponse<T> =
  | { status: 'success'; data: T }
  | { status: 'error'; message: string };

// Type guard for success response
function isSuccess<T>(response: ApiResponse<T>): response is { status: 'success'; data: T } {
  return response.status === 'success';
}

// Example usage:
const response: ApiResponse<number> = { status: 'success', data: 42 };

if (isSuccess(response)) {
  console.log('Data:', response.data);
} else {
  console.error('Error:', response.message);
}
```

- The `status` field discriminates between the two variants.
- The `isSuccess` function narrows the type to the success variant.

Here's a Python implementation of a Trie (prefix tree) with `insert`, `search`, and `starts_with` methods:

```python
class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def starts_with(self, prefix: str) -> bool:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True
```

### Example usage:

```python
trie = Trie()
trie.insert("apple")
print(trie.search("apple"))    # True
print(trie.search("app"))      # False
print(trie.starts_with("app")) # True
trie.insert("app")
print(trie.search("app"))      # True
```

This implementation uses a dictionary to store children nodes for each character. The `is_end_of_word` flag marks the end of a valid word.

