Here's an example of how to use the IntersectionObserver API to lazy-load images as they scroll into view:

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Lazy Load Images with IntersectionObserver</title>
  <style>
    img {
      display: block;
      margin: 20px auto;
      max-width: 100%;
      height: auto;
      min-height: 200px;
      background: #f0f0f0;
    }
  </style>
</head>
<body>

  <!-- Images with data-src for lazy loading -->
  <img data-src="https://via.placeholder.com/600x400?text=Image+1" alt="Image 1" />
  <img data-src="https://via.placeholder.com/600x400?text=Image+2" alt="Image 2" />
  <img data-src="https://via.placeholder.com/600x400?text=Image+3" alt="Image 3" />
  <img data-src="https://via.placeholder.com/600x400?text=Image+4" alt="Image 4" />
  <img data-src="https://via.placeholder.com/600x400?text=Image+5" alt="Image 5" />

  <script>
    document.addEventListener("DOMContentLoaded", () => {
      const images = document.querySelectorAll('img[data-src]');

      const options = {
        root: null, // viewport
        rootMargin: '0px',
        threshold: 0.1 // 10% of image visible
      };

      const loadImage = (image) => {
        image.src = image.getAttribute('data-src');
        image.removeAttribute('data-src');
      };

      const observer = new IntersectionObserver((entries, observer) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            loadImage(entry.target);
            observer.unobserve(entry.target);
          }
        });
      }, options);

      images.forEach(img => {
        observer.observe(img);
      });
    });
  </script>

</body>
</html>
```

### Explanation:
- Images have a `data-src` attribute with the actual image URL.
- The `src` attribute is initially empty or can be a placeholder.
- The IntersectionObserver watches each image.
- When an image is about to enter the viewport (10% visible), the observer callback sets the `src` attribute to the value of `data-src`, triggering the image load.
- The observer then unobserves that image to avoid unnecessary checks.

This approach improves page load performance by loading images only when needed.

You can create a drag-and-drop sortable list using the native HTML5 Drag and Drop API by handling drag events (`dragstart`, `dragover`, `drop`, etc.) on list items and updating the DOM accordingly.

Here's a simple example of a sortable list:

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>Sortable List with HTML5 Drag and Drop</title>
<style>
  ul {
    list-style: none;
    padding: 0;
    width: 200px;
  }
  li {
    padding: 8px 12px;
    margin: 4px 0;
    background: #eee;
    border: 1px solid #ccc;
    cursor: move;
  }
  li.dragging {
    opacity: 0.5;
  }
</style>
</head>
<body>

<ul id="sortable-list">
  <li draggable="true">Item 1</li>
  <li draggable="true">Item 2</li>
  <li draggable="true">Item 3</li>
  <li draggable="true">Item 4</li>
</ul>

<script>
  const list = document.getElementById('sortable-list');
  let draggedItem = null;

  list.addEventListener('dragstart', (e) => {
    if (e.target && e.target.nodeName === 'LI') {
      draggedItem = e.target;
      e.target.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
      // Required for Firefox to show dragging
      e.dataTransfer.setData('text/plain', '');
    }
  });

  list.addEventListener('dragend', (e) => {
    if (draggedItem) {
      draggedItem.classList.remove('dragging');
      draggedItem = null;
    }
  });

  list.addEventListener('dragover', (e) => {
    e.preventDefault(); // Necessary to allow drop
    if (e.target && e.target.nodeName === 'LI' && e.target !== draggedItem) {
      const bounding = e.target.getBoundingClientRect();
      const offset = e.clientY - bounding.top;
      if (offset > bounding.height / 2) {
        e.target.style['border-bottom'] = '2px solid blue';
        e.target.style['border-top'] = '';
      } else {
        e.target.style['border-top'] = '2px solid blue';
        e.target.style['border-bottom'] = '';
      }
    }
  });

  list.addEventListener('dragleave', (e) => {
    if (e.target && e.target.nodeName === 'LI') {
      e.target.style['border-bottom'] = '';
      e.target.style['border-top'] = '';
    }
  });

  list.addEventListener('drop', (e) => {
    e.preventDefault();
    if (e.target && e.target.nodeName === 'LI' && draggedItem) {
      e.target.style['border-bottom'] = '';
      e.target.style['border-top'] = '';

      const bounding = e.target.getBoundingClientRect();
      const offset = e.clientY - bounding.top;

      if (offset > bounding.height / 2) {
        e.target.insertAdjacentElement('afterend', draggedItem);
      } else {
        e.target.insertAdjacentElement('beforebegin', draggedItem);
      }
    }
  });
</script>

</body>
</html>
```

### How it works:
- Each `<li>` is made draggable with `draggable="true"`.
- On `dragstart`, we store the dragged item and add a class for styling.
- On `dragover`, we prevent default to allow dropping and visually indicate where the dragged item will be inserted (top or bottom border).
- On `drop`, we insert the dragged item before or after the target item based on the mouse position.
- On `dragend` and `dragleave`, we clean up styles.

This approach uses only native HTML5 Drag and Drop API without any external libraries.

---

If you want a more robust solution (handling edge cases, touch devices, accessibility), consider libraries like [SortableJS](https://sortablejs.github.io/Sortable/).

